sp_widget.client_script:
api.controller=function() {
  /* widget controller */
  var c = this;
};

sp_widget.css:
.request-page{
    padding:60px;
    background:#f5f7fa;
    min-height:100vh;
}

.request-header{
    text-align:center;
    margin-bottom:50px;
}

.request-header h1{
    font-size:42px;
    color:#0F4C81;
    margin-bottom:15px;
}

.request-header p{
    max-width:850px;
    margin:auto;
    font-size:18px;
    color:#666;
    line-height:1.7;
}

.request-info{
    display:flex;
    justify-content:center;
    gap:30px;
    flex-wrap:wrap;
}

.info-card{
    width:320px;
    background:#ffffff;
    border-radius:12px;
    padding:30px;
    box-shadow:0 8px 18px rgba(0,0,0,.10);
    transition:0.3s;
}

.info-card:hover{
    transform:translateY(-6px);
}

.info-card h2{
    color:#0F4C81;
    margin-bottom:20px;
}

.info-card p{
    color:#555;
    line-height:1.7;
}

.info-card ul{
    padding-left:20px;
    color:#555;
    line-height:2;
}

.request-btn-section{
    text-align:center;
    margin-top:60px;
}

.request-btn{
    display:inline-block;
    background:#0F4C81;
    color:#ffffff;
    padding:16px 40px;
    border:none;
    border-radius:8px;
    font-size:18px;
    font-weight:bold;
    cursor:pointer;
    transition:0.3s;
    text-decoration:none;
}

.request-btn:hover{
    background:#0B3A62;
    color:#ffffff;
    text-decoration:none;
}

@media (max-width:992px){

    .request-info{
        gap:20px;
    }

    .info-card{
        width:280px;
    }

}

@media (max-width:768px){

    .request-page{
        padding:40px 20px;
    }

    .request-header h1{
        font-size:32px;
    }

    .request-header p{
        font-size:16px;
    }

    .request-info{
        flex-direction:column;
        align-items:center;
    }

    .info-card{
        width:100%;
        max-width:400px;
    }

    .request-btn{
        width:100%;
        max-width:320px;
    }

}
